#include <iostream>
#include <algorithm>
using namespace std;
int main()
{
    int n;
    cin>>n;
    for(int i=0;i<=n-1;i++)
    {
        string s;
        int sum=0;
        cin>>s;
        reverse(s.begin(),s.end());
        for(int i=0;i<=s.size()-1;i++)
        {
            if(i%2==1)
            {
                sum=sum+s[i]-'0';
            }
            else
            {
                int t=s[i]-'0';
                t*=7;
                while(t>9)
                {
                    t=t/10+t%10;
                }
                sum+=t;
            }
        }
        if(sum%8==0)
        {
            cout<<"T"<<endl;
        }
        else
        {
            cout<<"F"<<endl;
        }
    }
    return 0;
}
